class Solution:
    def maximumTime(self, time):
        best = None
        for h in range(24):
            for m in range(60):
                cand = '%02d:%02d' % (h, m)
                ok = all(time[i] == '?' or time[i] == cand[i] for i in range(5))
                if ok:
                    best = cand
        return best

